```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    pid_t pid = fork();

    if (pid == 0) { // Child process
        int fd[2];
        pipe(fd); // Create a pipe

        // Redirect input and output to the pipe
        close(fd[1]); // Close the write end in the child
        dup2(fd[0], 0); // Duplicate the read end to stdin
        close(fd[0]); // Close the read end

        // Redirect output to the pipe
        close(fd[0]); // Close the read end in the child
        dup2(fd[1], 1); // Duplicate the write end to stdout
        close(fd[1]); // Close the write end

        // Execute the command
        execlp("your_command", "your_command", (char*)0);
        std::cerr << "Error executing command\n";
        exit(1);
    } else if (pid > 0) { // Parent process
        // Wait for the child to finish
        waitpid(pid, nullptr, 0);
        std::cout << "Child process finished.\n";
    } else {
        std::cerr << "Fork failed\n";
    }

    return 0;
}
```

Replace `"your_command"` with the command you want to run. This example uses a pipe to connect the child process's input and output.
